  ('cpa-moex-00731', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核證據的適切性，下列敘述何者正確？ 查核證據的適切性係指所獲得查核證據的數量 查核證據的適切性係指所獲得查核證據的可靠性或攸關性，但無須兩者兼備 查核證據的攸關性係指對財務報表使用者決策的影響程度 應收帳款之函證，對應收帳款存在聲明提供高度適切的查核證據，但對應收帳款評價聲明的適 切性則較低', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "b31a6169dd18", "answer_pdf_sha1": "13aaf559a1eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
